# Unit Tests for `safe_divide`

```python
import pytest
from math import isnan, isinf

# Assuming the function is in a module called `math_utils`
# from math_utils import safe_divide

def safe_divide(a: float, b: float, default: float = 0.0) -> float:
    try:
        return a / b
    except ZeroDivisionError:
        return default


class TestSafeDivideHappyPath:
    """Tests for normal, expected use cases."""

    def test_divides_two_positive_integers(self):
        assert safe_divide(10, 2) == 5.0

    def test_divides_two_positive_floats(self):
        assert safe_divide(7.5, 2.5) == 3.0

    def test_divides_negative_by_positive(self):
        assert safe_divide(-10, 2) == -5.0

    def test_divides_positive_by_negative(self):
        assert safe_divide(10, -2) == -5.0

    def test_divides_two_negatives(self):
        assert safe_divide(-10, -2) == 5.0

    def test_divides_zero_numerator(self):
        # 0 / non-zero is valid and should equal 0.0
        assert safe_divide(0, 5) == 0.0

    def test_returns_float_type(self):
        result = safe_divide(10, 2)
        assert isinstance(result, float)

    def test_division_yielding_fraction(self):
        assert safe_divide(1, 4) == 0.25

    def test_division_by_one(self):
        assert safe_divide(42.0, 1) == 42.0


class TestSafeDivideZeroDivision:
    """Tests for the divide-by-zero edge case."""

    def test_zero_divisor_returns_default(self):
        assert safe_divide(10, 0) == 0.0

    def test_zero_divisor_returns_custom_default(self):
        assert safe_divide(10, 0, default=99.0) == 99.0

    def test_zero_divided_by_zero_returns_default(self):
        assert safe_divide(0, 0) == 0.0

    def test_zero_divided_by_zero_with_custom_default(self):
        assert safe_divide(0, 0, default=-1.0) == -1.0

    def test_negative_numerator_with_zero_denominator(self):
        assert safe_divide(-5, 0, default=42.0) == 42.0

    def test_default_can_be_negative(self):
        assert safe_divide(1, 0, default=-100.0) == -100.0

    def test_default_can_be_nan(self):
        result = safe_divide(1, 0, default=float("nan"))
        assert isnan(result)

    def test_default_can_be_infinity(self):
        result = safe_divide(1, 0, default=float("inf"))
        assert isinf(result) and result > 0


class TestSafeDivideFloatEdgeCases:
    """Tests for floating-point edge cases."""

    def test_division_by_very_small_number(self):
        # Note: 1e-300 is non-zero, so no ZeroDivisionError occurs
        result = safe_divide(1.0, 1e-300)
        assert result == 1e300

    def test_division_resulting_in_infinity_does_not_raise(self):
        # Float division that overflows yields inf rather than raising
        result = safe_divide(1e308, 1e-308)
        assert isinf(result)

    def test_float_zero_divisor_returns_default(self):
        # 0.0 (float) also raises ZeroDivisionError
        assert safe_divide(5.0, 0.0, default=7.0) == 7.0

    def test_negative_zero_divisor_returns_default(self):
        # -0.0 also triggers ZeroDivisionError in Python
        assert safe_divide(5.0, -0.0, default=3.0) == 3.0

    def test_infinity_numerator(self):
        result = safe_divide(float("inf"), 2)
        assert isinf(result)

    def test_nan_numerator_propagates(self):
        result = safe_divide(float("nan"), 2)
        assert isnan(result)

    def test_infinity_divided_by_infinity_is_nan(self):
        result = safe_divide(float("inf"), float("inf"))
        assert isnan(result)


class TestSafeDivideErrorCases:
    """Tests for invalid input types that should propagate errors."""

    def test_string_numerator_raises_type_error(self):
        with pytest.raises(TypeError):
            safe_divide("10", 2)

    def test_string_denominator_raises_type_error(self):
        with pytest.raises(TypeError):
            safe_divide(10, "2")

    def test_none_numerator_raises_type_error(self):
        with pytest.raises(TypeError):
            safe_divide(None, 2)

    def test_none_denominator_raises_type_error(self):
        with pytest.raises(TypeError):
            safe_divide(10, None)

    def test_list_input_raises_type_error(self):
        with pytest.raises(TypeError):
            safe_divide([1, 2], 2)


